const addButton=document.getElementById("addButton"),editButtons=document.querySelectorAll(".edit-button"),insertModal=document.getElementById("insertModal"),editModal=document.getElementById("editModal"),closeButtons=document.querySelectorAll(".close");addButton.addEventListener("click",()=>{insertModal.style.display="block"}),editButtons.forEach(t=>{t.addEventListener("click",t=>{editModal.style.display="block"})}),closeButtons.forEach(t=>{t.addEventListener("click",()=>{insertModal.style.display="none",editModal.style.display="none"})}),window.addEventListener("click",t=>{t.target===insertModal&&(insertModal.style.display="none"),t.target===editModal&&(editModal.style.display="none")});const setPoinByTingkat=(t,e)=>{let n="";switch(t){case"I":n=32;break;case"II":n=16;break;case"III":n=8;break;case"IV":n=4;break;case"V":n=2;break;default:n=""}e.value=n};document.addEventListener("change",t=>{if("tingkat"===t.target.id){const e=t.target.value,n=t.target.closest("form").querySelector("#poin");setPoinByTingkat(e,n)}});const tatibTable=document.getElementById("tatib-table");tatibTable.addEventListener("click",function(t){if(t.target.closest(".edit-button")){const e=t.target.closest("tr").querySelectorAll("td");document.getElementById("admin").value=e[1].textContent,document.getElementById("editKonten").value=e[2].textContent,document.getElementById("tingkat").value=e[3].textContent,document.getElementById("poin").value=e[4].textContent,editModal.style.display="block"}});